const express = require('express');
const jwt = require('jsonwebtoken');
const jwksClient = require('jwks-rsa');
const app = express();

const client = jwksClient({
  jwksUri: process.env.JWT_JWKS_URI || 'https://your-domain.com/.well-known/jwks.json',
  cache: true,
  cacheMaxEntries: 5,
  cacheMaxAge: 600000,
  timeout: 30000
});

const verifyToken = (req, res, next) => {
  const authHeader = req.headers.authorization;
  
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({
      error: 'Unauthorized',
      message: 'Missing or invalid Authorization header'
    });
  }

  const token = authHeader.substring(7);

  if (!token) {
    return res.status(401).json({
      error: 'Unauthorized',
      message: 'No access token provided'
    });
  }

  const verifyOptions = {
    audience: process.env.JWT_AUDIENCE || 'your-api-audience',
    issuer: process.env.JWT_ISSUER || 'https://your-domain.com/',
    algorithms: ['RS256']
  };

  jwt.verify(token, getPublicKey, verifyOptions, (err, decoded) => {
    if (err) {
      if (err.name === 'TokenExpiredError') {
        return res.status(401).json({
          error: 'Unauthorized',
          message: 'Token has expired'
        });
      }
      if (err.name === 'JsonWebTokenError') {
        return res.status(401).json({
          error: 'Unauthorized',
          message: 'Invalid token'
        });
      }
      return res.status(401).json({
        error: 'Unauthorized',
        message: 'Token verification failed'
      });
    }

    req.user = decoded;
    next();
  });
};

const getPublicKey = (header, callback) => {
  client.getSigningKey(header.kid, (err, key) => {
    if (err) {
      return callback(err);
    }
    const signingKey = key.publicKey || key.rsaPublicKey;
    callback(null, signingKey);
  });
};

app.use(verifyToken);

app.get('/api/protected', (req, res) => {
  res.json({
    message: 'Access granted',
    user: req.user
  });
});

app.listen(3000, () => {
  console.log('Resource server listening on port 3000');
});